#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch>='0'&&ch<='9')res=res*10+(ch^48),ch=getchar();return res; 
}
const int N=5e5+10;
int head[N],des[N<<1],nxt[N<<1],cgt,deg[N],n,m;
vector<int> ou;bool kpp[N];
inline bool Output()
{
	if(int(ou.size())==n||ou.size()==0)return false;
	else
	{
		printf("Yes\n%d\n",n-int(ou.size()));
		memset(kpp+1,0,n);for(int v:ou)kpp[v]=true;
		rep(1,n,i)if(!kpp[i])printf("%d ",i);puts("");
		return true;
	}
}
template<typename T> inline void Clear(vector<T> &v){vector<T> t;v.swap(t);}
inline void ins(int x,int y)
{
	nxt[++cgt]=head[x];++deg[des[head[x]=cgt]=y];
	nxt[++cgt]=head[y];++deg[des[head[y]=cgt]=x];
}
int h2[N],d2[N<<1],n2[N<<1],c2;
inline void Ins(int x,int y){n2[++c2]=h2[x];d2[h2[x]=c2]=y;n2[++c2]=h2[y];d2[h2[y]=c2]=x;}
int dep[N],fa[N],que[N],H,T;
inline void bfs(int s)
{
	memset(dep+1,0,n*sizeof(int));
	dep[que[H=T=0]=s]=1;fa[s]=0;
	while(H<=T)
	{
		int u=que[H++];
		for(int i=head[u];i;i=nxt[i])
		{
			int v=des[i];if(!dep[v])
			{
				dep[que[++T]=v]=dep[u]+1;
				fa[v]=u;
			}
		}
	}
}
bool flag;int fu,fv,cdt,vis[N],g2[N],Mn;bool jud[N],xl[N];
inline void dfs(int u,int f=0)
{
//	printf("dfs %d\n",u);
	vis[u]=cdt;fa[u]=f;int mx=0;g2[u]=f?1:0;dep[u]=dep[f]+1;
	for(int i=h2[u];i;i=n2[i])
	{
		int v=d2[i];if(deg[v]!=2||v==f)continue;
		if(!vis[v])dfs(v,u); else if(dep[v]<dep[u]&&dep[v]>dep[mx])mx=v;++g2[u];
	}
	if(mx&&dep[u]-dep[mx]<Mn){flag=true;Mn=dep[u]-dep[mx];fu=u;fv=mx;}
//	printf("%d :: %d %d %d (%d,%d)\n",u,mx,dep[u]-dep[mx],Mn,fu,fv);
//	if(flag)return;if(mx){flag=true;fu=u;fv=mx;}
}
int rt;inline void dfs0(int u,int f=0)
{
	ou.push_back(u);
	for(int i=head[u];i;i=nxt[i])
	{
		int v=des[i];if(v==f)continue;
		if(v==rt)return;
	}
	for(int i=h2[u];i;i=n2[i])
	{
		int v=d2[i];if(v==f)continue;
		dfs0(v,u);break;
	}
}
inline void Solve()
{
	n=read();m=read();
	memset(head+1,0,n*sizeof(int));cgt=0;
	memset(deg+1,0,n*sizeof(int));Clear(ou);
	memset(g2+1,0,n*sizeof(int));
	rep(1,m,i)ins(read(),read());
//	rep(1,n,i)printf("%d ",deg[i]);puts("");return;
	int cnt1=0;rep(1,n,i)
	{
		if((deg[i]%=3)==0)
		{
			ou.push_back(i);
			return;
		}
		cnt1+=(deg[i]==1);
	}
	
	if(cnt1>=2)
	{
		rep(1,n,u)if(deg[u]==1)
		{
			bfs(u);Mn=0x3f3f3f3f;
			rep(u+1,n,v)if(deg[v]==1)Mn=min(Mn,dep[v]);
			rep(u+1,n,v)if(deg[v]==1&&dep[v]==Mn)
			{
				int w=v;
				while(w){ ou.push_back(w); w=fa[w]; }
				return;
			}
		}
	}
	else
	{
		memset(h2+1,0,n*sizeof(int));c2=0;
		for(int i=1;i<=cgt;i+=2)
		{
			int u=des[i],v=des[i+1];
			if(deg[u]==2&&deg[v]==2)Ins(u,v);
		}
		memset(dep+1,0,n*sizeof(int));
		memset(vis+1,0,n*sizeof(int));flag=false;
		memset(jud+1,0,n);cdt=0;
//		puts("QAQQAQ");
		rep(1,n,u)if(deg[u]==2&&!vis[u])
		{
//			puts("QAQAQ");
			Mn=0x3f3f3f3f;
			++cdt;dfs(u);if(flag)
			{
//				printf("QAQ :: %d %d\n",fu,fv);
				int w=fu;
				while(true){ou.push_back(w);if(w==fv)break;w=fa[w];}
				return;
			}
		}
//		rep(1,n,i)printf("%d ",vis[i]);puts("");
		for(rt=1;rt<=n;++rt)if(deg[rt]==1)
		{
			int cnt=0;
			for(int i=head[rt];i;i=nxt[i])
			{
				int v=des[i];
				if(g2[v]==1&&!jud[vis[v]])
				{
					flag=false;dfs0(v,rt);
					jud[vis[v]]=true;
//					printf("WSW :: %d %d\n",v,g2[v]);
					if((++cnt)==2)break;
				}
			}
			if(cnt<=1)
			{
				Clear(ou);return;
			}
			ou.push_back(rt);return;
		}
	}
}
int main()
{
//	FIN("Map.in");
//	FOUT("yourans.out");
	int T=read();
	while(T--)
	{
		Solve();
		if(!Output())puts("No");
	}
	
}
